var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"쭉 좋아했습니다.","JPN":"ずっと好きでした。","ENG":"I've always liked you.","TWN":"我一直喜歡你。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"제 마음을...... 받아 주세요.","JPN":"私の気持ちを……受け取ってください。","ENG":"Please accept... my heart.","TWN":"這是我的一點心意……請收下吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"이건...... 초콜릿?","JPN":"これは……チョコレート？","ENG":"This is... Chocolate?","TWN":"這是……巧克力？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"네! 발렌타인은 이렇게 사랑을 고백하는 날이잖아요?","JPN":"はい！\\nバレンタインデーは、こうして愛を告白する日でしょう？","ENG":"Yes! Valentine's Day is the day you show your love with chocolate, right?","TWN":"嗯！情人節是告白的節日嘛。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"받아 주실 거죠?","JPN":"受け取ってくれますよね？","ENG":"I hope you accept it.","TWN":"你會收下吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"......마음은 알겠지만, 미안.","JPN":"……気持ちはわかったけど、ごめん。","ENG":"I appreciate the thought, but I'm sorry.","TWN":"……我收到妳的心意了。但……抱歉。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"난 이런 상업성 짙은 행사는 질색이라서.","JPN":"僕はこういう商業的なお祭り騒ぎは嫌いなんだ。","ENG":"I really don't like these sort of corporate schemes.","TWN":"我可不喜歡商業性這麼濃的活動。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"그 날, 나는 사랑을 잃었다.","JPN":"あの日、私は愛を失った。","ENG":"That day, I lost my love.","TWN":"那天，我失戀了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"발렌타인의 초콜릿이라면 불가능한 사랑도 마법처럼 이뤄질 거란 착각에 빠졌던 것이다.","JPN":"バレンタインチョコなら、\\n不可能な恋も魔法のように叶うと勘違いしていたのだ。","ENG":"I was delusional to think that Valentine's Day chocolate would magically make my love come true.","TWN":"那時我陷入了一種錯覺，誤以為情人節的巧克力像魔法一樣，能實現不可能的愛戀。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만...... 초콜릿 따위가 그런 마법 같은 사랑을 이뤄 줄 리 없었다.","JPN":"だが……たかがチョコレートが、恋を叶えてくれるはずはない。","ENG":"But there was no magic in the chocolate.","TWN":"但是……巧克力而已，沒有讓我得到愛情的魔力。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"큭큭...... 그래, 초콜릿은 아무 것도 아니야.","JPN":"ククッ……そう、チョコレートには何の力もないの。","ENG":"Hah hah. No. Chocolate is nothing.","TWN":"哈哈哈……是啊，巧克力算什麼呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"초콜릿의 달콤함은 아무 것도 바꾸지 못해.","JPN":"チョコレートの甘さは何一つ変えることができないわ。","ENG":"The sweetness of chocolate can't change anything.","TWN":"甜甜蜜蜜的巧克力什麼都改變不了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 난 할 수 있어. 모든 걸 바꿀 수 있지.","JPN":"でも、私はできる。すべてを変えることができるの。","ENG":"But I can. I can change everything.","TWN":"但我可以啊，我可以改變一切。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"그렇게 되게 만들 거야.","JPN":"だから、変えてやるわ。","ENG":"I will change everything.","TWN":"我會去改變一切的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"그러니 모두 기대해.","JPN":"みんな、見てなさい。","ENG":"You all just watch.","TWN":"所以你們都等好了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>10년 뒤</color>      \\n관리국 산하, CS 미래식량개발연구부      ","JPN":"<color=#ffd34c>10年後</color>      \\n管理局傘下、CS未来食糧開発研究部      ","ENG":"<color=#ffd34c>10 years later</color>      \\nAdministration affiliated, CS Future Food R&D Department      ","TWN":"<color=#ffd34c>10年後</color>      \\n管理局, CS 未來糧食研究部"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STAFF1_NPC_NULL_NULL","text":{"KOREA":"자, 이번 주도 고생 많으셨습니다.","JPN":"では、今週もお疲れ様でした。","ENG":"Alright everyone, good work this week.","TWN":"各位這周辛苦了。"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STAFF2_NPC_NULL_NULL","text":{"KOREA":"저희 프로젝트의 결과물이 국민의 식탁에 오를 일도 이제 머지 않았군요.","JPN":"私たちのプロジェクトの成果が、国民の食卓にのぼる日も遠くないですね。","ENG":"It won't be long before the fruits of our labor will be on our citizen's tables.","TWN":"我們這次專案的成果很快就要對外公佈了。"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"STAFF2_NPC_NULL_NULL","text":{"KOREA":"어? 론 리 교수님은 오늘도 야근이신 건가요?","JPN":"あれ？　ローン・リー教授は、今日も残業ですか？","ENG":"Hmm? Professor Lone Lee, are you working late again tonight?","TWN":"加班？教授也是嗎？"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"아...... 예. 아직 시험해 보고 싶은 게 남아서요.","JPN":"あ……はい。まだ実験してみたいことがありまして。","ENG":"Ah... Yes. I still have some things I want to test out.","TWN":"啊……對的，還有些實驗沒做完。"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STAFF2_NPC_NULL_NULL","text":{"KOREA":"또 뭔가 멋대로 섞어서 드시려는 건 아니겠죠?","JPN":"また何か勝手に混ぜて、食べるつもりじゃありませんよね？","ENG":"You're not going to drink a random concoction again, are you?","TWN":"不，您又想拿各種東西隨便摻和著吃吧？"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"STAFF2_NPC_NULL_NULL","text":{"KOREA":"위험하다고요.","JPN":"危険ですよ。","ENG":"It's dangerous.","TWN":"都說了很危險啦。"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"글쎄요. 사람을 상대로 하는 먹거리 연구니까요.","JPN":"……私たちの研究は、人の食べ物ですから。","ENG":"Well, we're studying food for people.","TWN":"給人吃的食物，哪部行？"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"과학자로서 당연한 일입니다.","JPN":"科学者として当然のことをしたまでです。","ENG":"As a scientist, it's only natural that I want to try what I make.","TWN":"那能賺錢，而且對科學家來說沒什麼奇怪的。"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"STAFF2_NPC_NULL_NULL","text":{"KOREA":"하아, 전 경고했어요.","JPN":"はあ……私は警告しましたからね。","ENG":"*Sigh* I warned you.","TWN":"錢啊？怎麼又再說這個？"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"STAFF1_NPC_NULL_NULL","text":{"KOREA":"뭐, 론 리 교수님이 그러는 거야 어제 오늘 일이 아니잖아요.","JPN":"まあ、ローン・リー教授の実験は、いつものことじゃないですか。","ENG":"Well, this isn't the first time Professor Lone Lee has done this.","TWN":"唉，教授這樣也不是一天兩天了，"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"STAFF1_NPC_NULL_NULL","text":{"KOREA":"빨리 재고 확인이나 하고 퇴근하죠.","JPN":"さっさと在庫を確認して帰りましょう。","ENG":"Let's just check our inventory and get out of here.","TWN":"趕緊確認過庫存然後下班吧。"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"STAFF1_NPC_NULL_NULL","text":{"KOREA":"하나, 둘, 셋......","JPN":"いち、に、さん……","ENG":"One, two, three...","TWN":"一，二，三……"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"STAFF1_NPC_NULL_NULL","text":{"KOREA":"......어라? 여기 있던 4번 샘플이 어디로 갔지?","JPN":"あれ……？　ここに置いた4番サンプルがない…？","ENG":"Err? What happened to Sample No. 4 that was here?","TWN":"……嗯？這兒放著的4號樣品呢？哪兒去了？"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"STAFF2_NPC_NULL_NULL","text":{"KOREA":"식용 부적합이라서 폐기한 거 아닐까요?","JPN":"食用不適合サンプルだから廃棄したんじゃないですか？","ENG":"Maybe it got thrown out because it was inedible?","TWN":"是不是因為不適合食用，被廢棄了？"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"STAFF1_NPC_NULL_NULL","text":{"KOREA":"벌써......? 아직 보고도 안 올렸는데!","JPN":"破棄？　まだ報告も済んでないのに！","ENG":"Already? But I hadn't even reported it yet!","TWN":"這就已經……？明明報告都還沒提交！"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"STAFF2_NPC_NULL_NULL","text":{"KOREA":"됐어요. 먹지도 못하는 건데.","JPN":"いいじゃないですか。どうせ食べられないんだし。","ENG":"Don't worry. It wasn't edible, anyway.","TWN":"算了，反正也是吃不了的東西。"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"STAFF2_NPC_NULL_NULL","text":{"KOREA":"기록을 남겨둘 바엔 아예 지워버리는 편이 낫겠죠.","JPN":"無駄な記録を残すより、さっさと消した方がいいですよ。","ENG":"It's better we have no record of it.","TWN":"與其留下記錄，不如直接刪掉好了。"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"STAFF1_NPC_NULL_NULL","text":{"KOREA":"그런가?","JPN":"そうかな……","ENG":"Maybe you're right.","TWN":"是嗎？"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"STAFF2_NPC_NULL_NULL","text":{"KOREA":"그럼 주말 잘 보내세요!","JPN":"それじゃあ、皆さん良い週末を！","ENG":"Well, then have a good weekend!","TWN":"週末愉快！"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"후후...... 다들 주말엔 쉬시나 보군요?","JPN":"ふふ……皆さん、週末はお休みなんですね？","ENG":"Hah hah... I'm guessing everyone has plans for this weekend?","TWN":"呼……看來大家週末都休息啊？"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"STAFF1_NPC_NULL_NULL","text":{"KOREA":"하하, 그래야죠. 이번 주말은 특별한 날이잖아요?","JPN":"ハハハ、もちろんです。今週末は特別な日ですから。","ENG":"Hah hah, of course. It's special, this weekend.","TWN":"哈哈，當然啦。這週末不是有那個特殊的日子嘛？"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"STAFF1_NPC_NULL_NULL","text":{"KOREA":"이번에 예약한 레스토랑이 유명한 쇼콜라티에가 디저트를 만드는 곳인데 정말 어렵게 자릴 구했거든요.","JPN":"この間、有名なショコラティエがデザートを作る人気レストランの予約がようやくできたんです。","ENG":"I jumped through hoops to get a reservation at a restaurant where a famous chocolatier works.","TWN":"我這次預約的餐廳裡做甜點的是很有名的巧克力專家，位子真的特別難訂。"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"STAFF2_NPC_NULL_NULL","text":{"KOREA":"저는 이번에 초콜릿을 만들어서 그이한테 선물하려고요.","JPN":"私は今年の彼氏へのプレゼントは、手作りチョコにしようと思っています。","ENG":"I want to make chocolate for my boyfriend this year.","TWN":"我準備做巧克力送給我那位來著。"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"STAFF2_NPC_NULL_NULL","text":{"KOREA":"교수님 몫도 만들어 드릴까요?","JPN":"教授の分もお作りしましょうか？","ENG":"Would you like some as well, Professor?","TWN":"要不要把教授那份也做了？"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"아뇨, 됐습니다.","JPN":"いいえ、結構です。","ENG":"No, thank you.","TWN":"算了吧。"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"기업이 만든 뻔한 상술에 놀아나는 건 질색이라서요.","JPN":"企業の商売に乗せられるのは、まっぴらなので。","ENG":"I despise crass commercialism that.","TWN":"這明顯是公司的行銷手段，我討厭被牽著鼻子走。"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"STAFF2_NPC_NULL_NULL","text":{"KOREA":"아하하...... 그, 그렇군요.","JPN":"あはは……そ、そうなんですね。","ENG":"Ah... Hah hah. I-I see.","TWN":"啊哈……是、是嗎。"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"STAFF2_NPC_NULL_NULL","text":{"KOREA":"그럼 다음 주에 뵙겠습니다.","JPN":"それでは、また来週。","ENG":"Well then, I'll see you next week.","TWN":"那下周見。"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"초콜릿이라......","JPN":"チョコレート……","ENG":"Chocolate...","TWN":"巧克力這種東西……"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"카카오매스...... 설탕...... 생크림...... 가염버터......","JPN":"カカオマス……砂糖……生クリーム……有塩バター……","ENG":"Cacao mass... Sugar... Whipped cream... Salted butter...","TWN":"可可豆……砂糖……生奶油……加鹽奶油……"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그리고...... 바로 이것!","JPN":"そして……これ！","ENG":"And... This!","TWN":"還有……這個！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MONSTER_EXTRA_NULL_NULL","text":{"KOREA":"크르르르르르......","JPN":"グルルルルルル……","ENG":"Grrrrrrrr...","TWN":"卡啦啦啦啦啦……"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_FALL_DAMAGE_DOWN"},{"id":"L8_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"후후...... 완벽해. 걸작이야. 드디어 내 연구가 결실을 맺게 됐어.","JPN":"ふふ……完璧よ。傑作だわ。\\nやっと私の研究が実を結んだわ。","ENG":"Hah Hah... Perfect. It's a masterpiece. Finally, my research has come to fruition.","TWN":"嘿嘿……完美，這完全是傑作啊，我的研究終於有成果啦。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"마침 시간도 인간이 가장 잔인해질 수 있는 발렌타인데이 이브!","JPN":"しかも、時間も丁度、人間がもっとも残酷になれるバレンタインデーね！","ENG":"And today happens to be Valentine's Day Eve!","TWN":"還恰好是讓人變得最殘忍的時候——情人節前夕！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"으하하...... 상업성에 찌든 인간들에게 잊지 못할 기념일을 선사해 주지.","JPN":"あはは……企業に騙されてる人間どもに、\\n忘れられない記念日をプレゼントしてあげる。","ENG":"Mwa hah hah! I will present an unforgettable day to those who have succumbed to the temptations of capitalism.","TWN":"哈哈哈……我要給這些渾身商業味的人類一個難忘的紀念日。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"으하하하하하하!!!","JPN":"あははははははは！！！","ENG":"Mwa hah hah hah!","TWN":"啊哈哈哈哈哈哈！！！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_FALL_DAMAGE_DOWN"}]`);export{e as default};